        /// contains that name.
        queue: []const u8,

        message_count: u32,

        /// Number of consumers.
        /// Reports the number of active consumers for the queue. Note that consumers can
        /// suspend activity (Channel.Flow) in which case they do not appear in this count.
        consumer_count: u32,

        fn read(reader: *Reader) Error!DeclareOk {
            const queue = try reader.read_short_string();
            const message_count = try reader.read_int(u32);
            const consumer_count = try reader.read_int(u32);

