        pub const synchronous = true;

        reserved_1: u16 = 0,

        /// Specifies the name of the queue to purge.
        queue: []const u8,

        no_wait: bool,

        fn any(self: Purge) SendMethod {
            return .{ .queue_purge = self };
        }

        fn write(self: *const Purge, writer: *Writer) void {
            writer.write_int(u16, self.reserved_1);
            writer.write_short_string(self.queue);
            var bitset_1: stdx.BitSetType(8) = .{};
            bitset_1.set_value(0, self.no_wait);
            writer.write_int(u8, bitset_1.bits);
        }
