    /// Confirms a queue purge.
    /// This method confirms the purge of a queue.
    pub const PurgeOk = struct {
        pub const header: MethodHeader = .{ .class = 50, .method = 31 };
        pub const synchronous = true;

        /// Reports the number of messages purged.
        message_count: u32,

