    /// This method asks the server to start a "consumer", which is a transient request for
    /// messages from a specific queue. Consumers last as long as the channel they were
    /// declared on, or until the client cancels them.
    pub const Consume = struct {
        pub const header: MethodHeader = .{ .class = 60, .method = 20 };
        pub const synchronous = true;

        reserved_1: u16 = 0,

        /// Specifies the name of the queue to consume from.
        queue: []const u8,

        /// Specifies the identifier for the consumer. The consumer tag is local to a
        /// channel, so two clients can use the same consumer tags. If this field is
        /// empty the server will generate a unique tag.
        consumer_tag: []const u8,

        no_local: bool,

        no_ack: bool,

        /// Request exclusive access.
        /// Request exclusive consumer access, meaning only this consumer can access the
        /// queue.
        exclusive: bool,

        no_wait: bool,

        /// Arguments for declaration.
        /// A set of arguments for the consume. The syntax and semantics of these
        /// arguments depends on the server implementation.
        arguments: Table,

        fn any(self: Consume) SendMethod {
            return .{ .basic_consume = self };
        }

        fn write(self: *const Consume, writer: *Writer) void {
            writer.write_int(u16, self.reserved_1);
            writer.write_short_string(self.queue);
            writer.write_short_string(self.consumer_tag);
            var bitset_1: stdx.BitSetType(8) = .{};
            bitset_1.set_value(0, self.no_local);
            bitset_1.set_value(1, self.no_ack);
            bitset_1.set_value(2, self.exclusive);
            bitset_1.set_value(3, self.no_wait);
            writer.write_int(u8, bitset_1.bits);
            writer.write_table(self.arguments);
        }
