            return .{ .basic_cancel = self };
        }

        fn write(self: *const Cancel, writer: *Writer) void {
            writer.write_short_string(self.consumer_tag);
            var bitset_1: stdx.BitSetType(8) = .{};
            bitset_1.set_value(0, self.no_wait);
            writer.write_int(u8, bitset_1.bits);
        }
