            writer.write_int(u16, self.reserved_1);
            writer.write_short_string(self.exchange);
            writer.write_short_string(self.routing_key);
            var bitset_1: stdx.BitSetType(8) = .{};
            bitset_1.set_value(0, self.mandatory);
            bitset_1.set_value(1, self.immediate);
            writer.write_int(u8, bitset_1.bits);
        }
