    /// Return a failed message.
    /// This method returns an undeliverable message that was published with the "immediate"
    /// flag set, or an unroutable message published with the "mandatory" flag set. The
    /// reply code and text provide information about the reason that the message was
    /// undeliverable.
    pub const Return = struct {
        pub const header: MethodHeader = .{ .class = 60, .method = 50 };
        pub const synchronous = false;

        reply_code: u16,

        reply_text: []const u8,

        /// Specifies the name of the exchange that the message was originally published
        /// to.  May be empty, meaning the default exchange.
        exchange: []const u8,

        /// Message routing key.
        /// Specifies the routing key name specified when the message was published.
        routing_key: []const u8,

        fn read(reader: *Reader) Error!Return {
            const reply_code = try reader.read_int(u16);
            const reply_text = try reader.read_short_string();
            const exchange = try reader.read_short_string();
            const routing_key = try reader.read_short_string();

