    /// This method delivers a message to the client, via a consumer. In the asynchronous
    /// message delivery model, the client starts a consumer using the Consume method, then
    /// the server responds with Deliver methods as and when messages arrive for that
    /// consumer.
    pub const Deliver = struct {
        pub const header: MethodHeader = .{ .class = 60, .method = 60 };
        pub const synchronous = false;

        consumer_tag: []const u8,

        delivery_tag: u64,

        redelivered: bool,

        /// Specifies the name of the exchange that the message was originally published to.
        /// May be empty, indicating the default exchange.
        exchange: []const u8,

        /// Message routing key.
        /// Specifies the routing key name specified when the message was published.
        routing_key: []const u8,

        fn read(reader: *Reader) Error!Deliver {
            const consumer_tag = try reader.read_short_string();
            const delivery_tag = try reader.read_int(u64);
            const bitset_1 = try reader.read_bitset();
            const redelivered = bitset_1.is_set(0);
            const exchange = try reader.read_short_string();
            const routing_key = try reader.read_short_string();

            return .{
                .consumer_tag = consumer_tag,
                .delivery_tag = delivery_tag,
                .redelivered = redelivered,
                .exchange = exchange,
                .routing_key = routing_key,
            };
        }
    };

    /// Direct access to a queue.
    /// This method provides a direct access to the messages in a queue using a synchronous
    /// dialogue that is designed for specific types of application where synchronous
    /// functionality is more important than performance.
    pub const Get = struct {
        pub const header: MethodHeader = .{ .class = 60, .method = 70 };
        pub const synchronous = true;

        reserved_1: u16 = 0,

        /// Specifies the name of the queue to get a message from.
        queue: []const u8,

        no_ack: bool,

        fn any(self: Get) SendMethod {
            return .{ .basic_get = self };
        }

        fn write(self: *const Get, writer: *Writer) void {
            writer.write_int(u16, self.reserved_1);
            writer.write_short_string(self.queue);
            var bitset_1: stdx.BitSetType(8) = .{};
            bitset_1.set_value(0, self.no_ack);
            writer.write_int(u8, bitset_1.bits);
        }
    };

    /// Provide client with a message.
    /// This method delivers a message to the client following a get method. A message
    /// delivered by 'get-ok' must be acknowledged unless the no-ack option was set in the
    /// get method.
    pub const GetOk = struct {
        pub const header: MethodHeader = .{ .class = 60, .method = 71 };
        pub const synchronous = true;

        delivery_tag: u64,

        redelivered: bool,

        /// Specifies the name of the exchange that the message was originally published to.
        /// If empty, the message was published to the default exchange.
        exchange: []const u8,

        /// Message routing key.
        /// Specifies the routing key name specified when the message was published.
        routing_key: []const u8,

        message_count: u32,

        fn read(reader: *Reader) Error!GetOk {
            const delivery_tag = try reader.read_int(u64);
            const bitset_1 = try reader.read_bitset();
            const redelivered = bitset_1.is_set(0);
            const exchange = try reader.read_short_string();
            const routing_key = try reader.read_short_string();
            const message_count = try reader.read_int(u32);

            return .{
                .delivery_tag = delivery_tag,
                .redelivered = redelivered,
                .exchange = exchange,
                .routing_key = routing_key,
                .message_count = message_count,
            };
        }
    };

    /// Indicate no messages available.
    /// This method tells the client that the queue has no messages available for the
    /// client.
    pub const GetEmpty = struct {
        pub const header: MethodHeader = .{ .class = 60, .method = 72 };
        pub const synchronous = true;

        reserved_1: []const u8 = "",

        fn read(reader: *Reader) Error!GetEmpty {
            const reserved_1 = try reader.read_short_string();

            return .{
                .reserved_1 = reserved_1,
            };
        }
    };

    /// Acknowledge one or more messages.
    /// When sent by the client, this method acknowledges one or more
    /// messages delivered via the Deliver or Get-Ok methods.
    /// When sent by server, this method acknowledges one or more
    /// messages published with the Publish method on a channel in
    /// confirm mode.
    /// The acknowledgement can be for a single message or a set of
    /// messages up to and including a specific message.
    pub const Ack = struct {
        pub const header: MethodHeader = .{ .class = 60, .method = 80 };
        pub const synchronous = false;

        delivery_tag: u64,

        /// Acknowledge multiple messages.
        /// If set to 1, the delivery tag is treated as "up to and
        /// including", so that multiple messages can be acknowledged
        /// with a single method. If set to zero, the delivery tag
        /// refers to a single message. If the multiple field is 1, and
        /// the delivery tag is zero, this indicates acknowledgement of
        /// all outstanding messages.
        multiple: bool,

        fn read(reader: *Reader) Error!Ack {
            const delivery_tag = try reader.read_int(u64);
            const bitset_1 = try reader.read_bitset();
            const multiple = bitset_1.is_set(0);

            return .{
                .delivery_tag = delivery_tag,
                .multiple = multiple,
            };
        }

        fn any(self: Ack) SendMethod {
            return .{ .basic_ack = self };
        }

        fn write(self: *const Ack, writer: *Writer) void {
            writer.write_int(u64, self.delivery_tag);
            var bitset_1: stdx.BitSetType(8) = .{};
            bitset_1.set_value(0, self.multiple);
            writer.write_int(u8, bitset_1.bits);
        }
    };

    /// Reject an incoming message.
    /// This method allows a client to reject a message. It can be used to interrupt and
    /// cancel large incoming messages, or return untreatable messages to their original
    /// queue.
    pub const Reject = struct {
        pub const header: MethodHeader = .{ .class = 60, .method = 90 };
        pub const synchronous = false;

        delivery_tag: u64,

        /// Requeue the message.
        /// If requeue is true, the server will attempt to requeue the message.  If requeue
        /// is false or the requeue  attempt fails the messages are discarded or dead-lettered.
        requeue: bool,

        fn any(self: Reject) SendMethod {
            return .{ .basic_reject = self };
        }

        fn write(self: *const Reject, writer: *Writer) void {
            writer.write_int(u64, self.delivery_tag);
            var bitset_1: stdx.BitSetType(8) = .{};
            bitset_1.set_value(0, self.requeue);
            writer.write_int(u8, bitset_1.bits);
        }
    };

    /// Redeliver unacknowledged messages.
    /// This method asks the server to redeliver all unacknowledged messages on a
    /// specified channel. Zero or more messages may be redelivered.  This method
    /// is deprecated in favour of the synchronous Recover/Recover-Ok.
    pub const RecoverAsync = struct {
        pub const header: MethodHeader = .{ .class = 60, .method = 100 };
        pub const synchronous = false;

        /// Requeue the message.
        /// If this field is zero, the message will be redelivered to the original
        /// recipient. If this bit is 1, the server will attempt to requeue the message,
        /// potentially then delivering it to an alternative subscriber.
        requeue: bool,

        fn any(self: RecoverAsync) SendMethod {
            return .{ .basic_recover_async = self };
        }

        fn write(self: *const RecoverAsync, writer: *Writer) void {
            var bitset_1: stdx.BitSetType(8) = .{};
            bitset_1.set_value(0, self.requeue);
            writer.write_int(u8, bitset_1.bits);
        }
    };

    /// Redeliver unacknowledged messages.
    /// This method asks the server to redeliver all unacknowledged messages on a
    /// specified channel. Zero or more messages may be redelivered.  This method
    /// replaces the asynchronous Recover.
    pub const Recover = struct {
        pub const header: MethodHeader = .{ .class = 60, .method = 110 };
        pub const synchronous = false;

        /// Requeue the message.
        /// If this field is zero, the message will be redelivered to the original
        /// recipient. If this bit is 1, the server will attempt to requeue the message,
        /// potentially then delivering it to an alternative subscriber.
        requeue: bool,

        fn any(self: Recover) SendMethod {
            return .{ .basic_recover = self };
        }

        fn write(self: *const Recover, writer: *Writer) void {
            var bitset_1: stdx.BitSetType(8) = .{};
            bitset_1.set_value(0, self.requeue);
            writer.write_int(u8, bitset_1.bits);
        }
    };

    /// Confirm recovery.
    /// This method acknowledges a Basic.Recover method.
    pub const RecoverOk = struct {
        pub const header: MethodHeader = .{ .class = 60, .method = 111 };
        pub const synchronous = true;

        fn read(reader: *Reader) Error!RecoverOk {
            _ = reader;
            return .{};
        }
    };

    /// Reject one or more incoming messages.
    /// This method allows a client to reject one or more incoming messages. It can be
    /// used to interrupt and cancel large incoming messages, or return untreatable
    /// messages to their original queue.
    /// This method is also used by the server to inform publishers on channels in
    /// confirm mode of unhandled messages.  If a publisher receives this method, it
    /// probably needs to republish the offending messages.
    pub const Nack = struct {
        pub const header: MethodHeader = .{ .class = 60, .method = 120 };
        pub const synchronous = false;

        delivery_tag: u64,

        /// Reject multiple messages.
        /// If set to 1, the delivery tag is treated as "up to and
        /// including", so that multiple messages can be rejected
        /// with a single method. If set to zero, the delivery tag
        /// refers to a single message. If the multiple field is 1, and
        /// the delivery tag is zero, this indicates rejection of
        /// all outstanding messages.
        multiple: bool,

        /// Requeue the message.
        /// If requeue is true, the server will attempt to requeue the message.  If requeue
        /// is false or the requeue  attempt fails the messages are discarded or dead-lettered.
        /// Clients receiving the Nack methods should ignore this flag.
        requeue: bool,

        fn read(reader: *Reader) Error!Nack {
            const delivery_tag = try reader.read_int(u64);
            const bitset_1 = try reader.read_bitset();
            const multiple = bitset_1.is_set(0);
            const requeue = bitset_1.is_set(1);

            return .{
                .delivery_tag = delivery_tag,
                .multiple = multiple,
                .requeue = requeue,
            };
        }

        fn any(self: Nack) SendMethod {
            return .{ .basic_nack = self };
        }

        fn write(self: *const Nack, writer: *Writer) void {
            writer.write_int(u64, self.delivery_tag);
            var bitset_1: stdx.BitSetType(8) = .{};
            bitset_1.set_value(0, self.multiple);
            bitset_1.set_value(1, self.requeue);
            writer.write_int(u8, bitset_1.bits);
        }
    };
};

/// Work with transactions.
/// The Tx class allows publish and ack operations to be batched into atomic
/// units of work.  The intention is that all publish and ack requests issued
/// within a transaction will complete successfully or none of them will.
/// Servers SHOULD implement atomic transactions at least where all publish
/// or ack requests affect a single queue.  Transactions that cover multiple
/// queues may be non-atomic, given that queues can be created and destroyed
/// asynchronously, and such events do not form part of any transaction.
/// Further, the behaviour of transactions with respect to the immediate and
/// mandatory flags on Basic.Publish methods is not defined.
pub const Tx = struct {
    pub const class = 90;

    /// Select standard transaction mode.
    /// This method sets the channel to use standard transactions. The client must use this
    /// method at least once on a channel before using the Commit or Rollback methods.
    pub const Select = struct {
        pub const header: MethodHeader = .{ .class = 90, .method = 10 };
        pub const synchronous = true;

        fn any(self: Select) SendMethod {
            return .{ .tx_select = self };
        }

        fn write(self: *const Select, writer: *Writer) void {
            _ = self;
            _ = writer;
        }
    };

    /// Confirm transaction mode.
    /// This method confirms to the client that the channel was successfully set to use
    /// standard transactions.
    pub const SelectOk = struct {
        pub const header: MethodHeader = .{ .class = 90, .method = 11 };
        pub const synchronous = true;

        fn read(reader: *Reader) Error!SelectOk {
            _ = reader;
            return .{};
        }
    };

    /// Commit the current transaction.
    /// This method commits all message publications and acknowledgments performed in
    /// the current transaction.  A new transaction starts immediately after a commit.
    pub const Commit = struct {
        pub const header: MethodHeader = .{ .class = 90, .method = 20 };
        pub const synchronous = true;

        fn any(self: Commit) SendMethod {
            return .{ .tx_commit = self };
        }

        fn write(self: *const Commit, writer: *Writer) void {
            _ = self;
            _ = writer;
        }
    };

    /// Confirm a successful commit.
    /// This method confirms to the client that the commit succeeded. Note that if a commit
    /// fails, the server raises a channel exception.
    pub const CommitOk = struct {
        pub const header: MethodHeader = .{ .class = 90, .method = 21 };
        pub const synchronous = true;

        fn read(reader: *Reader) Error!CommitOk {
            _ = reader;
            return .{};
        }
    };

    /// Abandon the current transaction.
    /// This method abandons all message publications and acknowledgments performed in
    /// the current transaction. A new transaction starts immediately after a rollback.
    /// Note that unacked messages will not be automatically redelivered by rollback;
    /// if that is required an explicit recover call should be issued.
    pub const Rollback = struct {
        pub const header: MethodHeader = .{ .class = 90, .method = 30 };
        pub const synchronous = true;

        fn any(self: Rollback) SendMethod {
            return .{ .tx_rollback = self };
        }

        fn write(self: *const Rollback, writer: *Writer) void {
            _ = self;
            _ = writer;
        }
    };

    /// Confirm successful rollback.
    /// This method confirms to the client that the rollback succeeded. Note that if an
    /// rollback fails, the server raises a channel exception.
    pub const RollbackOk = struct {
        pub const header: MethodHeader = .{ .class = 90, .method = 31 };
        pub const synchronous = true;

        fn read(reader: *Reader) Error!RollbackOk {
            _ = reader;
            return .{};
        }
    };
};

/// Work with confirms.
/// The Confirm class allows publishers to put the channel in
/// confirm mode and subsequently be notified when messages have been
/// handled by the broker.  The intention is that all messages
/// published on a channel in confirm mode will be acknowledged at
/// some point.  By acknowledging a message the broker assumes
/// responsibility for it and indicates that it has done something
/// it deems reasonable with it.
/// Unroutable mandatory or immediate messages are acknowledged
/// right after the Basic.Return method. Messages are acknowledged
/// when all queues to which the message has been routed
/// have either delivered the message and received an
/// acknowledgement (if required), or enqueued the message (and
/// persisted it if required).
/// Published messages are assigned ascending sequence numbers,
/// starting at 1 with the first Confirm.Select method. The server
/// confirms messages by sending Basic.Ack methods referring to these
/// sequence numbers.
pub const Confirm = struct {
    pub const class = 85;

    /// This method sets the channel to use publisher acknowledgements.
    /// The client can only use this method on a non-transactional
    /// channel.
    pub const Select = struct {
        pub const header: MethodHeader = .{ .class = 85, .method = 10 };
        pub const synchronous = true;

        nowait: bool,

        fn any(self: Select) SendMethod {
            return .{ .confirm_select = self };
        }

        fn write(self: *const Select, writer: *Writer) void {
            var bitset_1: stdx.BitSetType(8) = .{};
            bitset_1.set_value(0, self.nowait);
            writer.write_int(u8, bitset_1.bits);
        }
    };

    /// This method confirms to the client that the channel was successfully
    /// set to use publisher acknowledgements.
    pub const SelectOk = struct {
        pub const header: MethodHeader = .{ .class = 85, .method = 11 };
        pub const synchronous = true;

        fn read(reader: *Reader) Error!SelectOk {
            _ = reader;
            return .{};
        }
    };
};

/// Methods sent by the AMQP server that must be handled by the client side,
/// marked by the spec with `<chassis name="client" implement="MUST|MAY"/>`.
pub const ReceiveMethod = union(ReceiveMethod.Tag) {
    pub const Tag = enum(u32) {
        connection_start = @bitCast(Connection.Start.header),
        connection_secure = @bitCast(Connection.Secure.header),
        connection_tune = @bitCast(Connection.Tune.header),
        connection_open_ok = @bitCast(Connection.OpenOk.header),
        connection_close = @bitCast(Connection.Close.header),
        connection_close_ok = @bitCast(Connection.CloseOk.header),
        connection_blocked = @bitCast(Connection.Blocked.header),
        connection_unblocked = @bitCast(Connection.Unblocked.header),
        connection_update_secret = @bitCast(Connection.UpdateSecret.header),
        channel_open_ok = @bitCast(Channel.OpenOk.header),
        channel_flow = @bitCast(Channel.Flow.header),
        channel_flow_ok = @bitCast(Channel.FlowOk.header),
        channel_close = @bitCast(Channel.Close.header),
        channel_close_ok = @bitCast(Channel.CloseOk.header),
        exchange_declare_ok = @bitCast(Exchange.DeclareOk.header),
        exchange_delete_ok = @bitCast(Exchange.DeleteOk.header),
        exchange_bind_ok = @bitCast(Exchange.BindOk.header),
        exchange_unbind_ok = @bitCast(Exchange.UnbindOk.header),
        queue_declare_ok = @bitCast(Queue.DeclareOk.header),
        queue_bind_ok = @bitCast(Queue.BindOk.header),
        queue_unbind_ok = @bitCast(Queue.UnbindOk.header),
        queue_purge_ok = @bitCast(Queue.PurgeOk.header),
        queue_delete_ok = @bitCast(Queue.DeleteOk.header),
        basic_qos_ok = @bitCast(Basic.QosOk.header),
        basic_consume_ok = @bitCast(Basic.ConsumeOk.header),
        basic_cancel = @bitCast(Basic.Cancel.header),
        basic_cancel_ok = @bitCast(Basic.CancelOk.header),
        basic_return = @bitCast(Basic.Return.header),
        basic_deliver = @bitCast(Basic.Deliver.header),
        basic_get_ok = @bitCast(Basic.GetOk.header),
        basic_get_empty = @bitCast(Basic.GetEmpty.header),
        basic_ack = @bitCast(Basic.Ack.header),
        basic_recover_ok = @bitCast(Basic.RecoverOk.header),
        basic_nack = @bitCast(Basic.Nack.header),
        tx_select_ok = @bitCast(Tx.SelectOk.header),
        tx_commit_ok = @bitCast(Tx.CommitOk.header),
        tx_rollback_ok = @bitCast(Tx.RollbackOk.header),
        confirm_select_ok = @bitCast(Confirm.SelectOk.header),
    };

    connection_start: Connection.Start,
    connection_secure: Connection.Secure,
    connection_tune: Connection.Tune,
    connection_open_ok: Connection.OpenOk,
    connection_close: Connection.Close,
    connection_close_ok: Connection.CloseOk,
    connection_blocked: Connection.Blocked,
    connection_unblocked: Connection.Unblocked,
    connection_update_secret: Connection.UpdateSecret,
    channel_open_ok: Channel.OpenOk,
    channel_flow: Channel.Flow,
    channel_flow_ok: Channel.FlowOk,
    channel_close: Channel.Close,
    channel_close_ok: Channel.CloseOk,
    exchange_declare_ok: Exchange.DeclareOk,
    exchange_delete_ok: Exchange.DeleteOk,
    exchange_bind_ok: Exchange.BindOk,
    exchange_unbind_ok: Exchange.UnbindOk,
    queue_declare_ok: Queue.DeclareOk,
    queue_bind_ok: Queue.BindOk,
    queue_unbind_ok: Queue.UnbindOk,
    queue_purge_ok: Queue.PurgeOk,
    queue_delete_ok: Queue.DeleteOk,
    basic_qos_ok: Basic.QosOk,
    basic_consume_ok: Basic.ConsumeOk,
    basic_cancel: Basic.Cancel,
    basic_cancel_ok: Basic.CancelOk,
    basic_return: Basic.Return,
    basic_deliver: Basic.Deliver,
    basic_get_ok: Basic.GetOk,
    basic_get_empty: Basic.GetEmpty,
    basic_ack: Basic.Ack,
    basic_recover_ok: Basic.RecoverOk,
    basic_nack: Basic.Nack,
    tx_select_ok: Tx.SelectOk,
    tx_commit_ok: Tx.CommitOk,
    tx_rollback_ok: Tx.RollbackOk,
    confirm_select_ok: Confirm.SelectOk,

    pub fn read(method_header: MethodHeader, reader: *Reader) Error!ReceiveMethod {
        const tag: Tag = @enumFromInt(@as(u32, @bitCast(method_header)));
        const value: ReceiveMethod = switch (tag) {
            .connection_start => .{
                .connection_start = try Connection.Start.read(reader),
            },
            .connection_secure => .{
                .connection_secure = try Connection.Secure.read(reader),
            },
            .connection_tune => .{
                .connection_tune = try Connection.Tune.read(reader),
            },
            .connection_open_ok => .{
                .connection_open_ok = try Connection.OpenOk.read(reader),
            },
            .connection_close => .{
                .connection_close = try Connection.Close.read(reader),
            },
            .connection_close_ok => .{
                .connection_close_ok = try Connection.CloseOk.read(reader),
            },
            .connection_blocked => .{
                .connection_blocked = try Connection.Blocked.read(reader),
            },
            .connection_unblocked => .{
                .connection_unblocked = try Connection.Unblocked.read(reader),
            },
            .connection_update_secret => .{
                .connection_update_secret = try Connection.UpdateSecret.read(reader),
            },
            .channel_open_ok => .{
                .channel_open_ok = try Channel.OpenOk.read(reader),
            },
            .channel_flow => .{
                .channel_flow = try Channel.Flow.read(reader),
            },
            .channel_flow_ok => .{
                .channel_flow_ok = try Channel.FlowOk.read(reader),
            },
            .channel_close => .{
                .channel_close = try Channel.Close.read(reader),
            },
            .channel_close_ok => .{
                .channel_close_ok = try Channel.CloseOk.read(reader),
            },
            .exchange_declare_ok => .{
                .exchange_declare_ok = try Exchange.DeclareOk.read(reader),
            },
            .exchange_delete_ok => .{
                .exchange_delete_ok = try Exchange.DeleteOk.read(reader),
            },
            .exchange_bind_ok => .{
                .exchange_bind_ok = try Exchange.BindOk.read(reader),
            },
            .exchange_unbind_ok => .{
                .exchange_unbind_ok = try Exchange.UnbindOk.read(reader),
            },
            .queue_declare_ok => .{
                .queue_declare_ok = try Queue.DeclareOk.read(reader),
            },
            .queue_bind_ok => .{
                .queue_bind_ok = try Queue.BindOk.read(reader),
            },
            .queue_unbind_ok => .{
                .queue_unbind_ok = try Queue.UnbindOk.read(reader),
            },
            .queue_purge_ok => .{
                .queue_purge_ok = try Queue.PurgeOk.read(reader),
            },
            .queue_delete_ok => .{
                .queue_delete_ok = try Queue.DeleteOk.read(reader),
            },
            .basic_qos_ok => .{
                .basic_qos_ok = try Basic.QosOk.read(reader),
            },
            .basic_consume_ok => .{
                .basic_consume_ok = try Basic.ConsumeOk.read(reader),
            },
            .basic_cancel => .{
                .basic_cancel = try Basic.Cancel.read(reader),
            },
            .basic_cancel_ok => .{
                .basic_cancel_ok = try Basic.CancelOk.read(reader),
            },
            .basic_return => .{
                .basic_return = try Basic.Return.read(reader),
            },
            .basic_deliver => .{
                .basic_deliver = try Basic.Deliver.read(reader),
            },
            .basic_get_ok => .{
                .basic_get_ok = try Basic.GetOk.read(reader),
            },
            .basic_get_empty => .{
                .basic_get_empty = try Basic.GetEmpty.read(reader),
            },
            .basic_ack => .{
                .basic_ack = try Basic.Ack.read(reader),
            },
            .basic_recover_ok => .{
                .basic_recover_ok = try Basic.RecoverOk.read(reader),
            },
            .basic_nack => .{
                .basic_nack = try Basic.Nack.read(reader),
            },
            .tx_select_ok => .{
                .tx_select_ok = try Tx.SelectOk.read(reader),
            },
            .tx_commit_ok => .{
                .tx_commit_ok = try Tx.CommitOk.read(reader),
            },
            .tx_rollback_ok => .{
                .tx_rollback_ok = try Tx.RollbackOk.read(reader),
            },
            .confirm_select_ok => .{
                .confirm_select_ok = try Confirm.SelectOk.read(reader),
            },
        };
        try reader.read_frame_end();
        return value;
    }
};

/// Methods sent by the client, marked by the spec
/// with `<chassis name="server" implement="MUST|MAY"/>`.
pub const SendMethod = union(SendMethod.Tag) {
    pub const Tag = enum(u32) {
        protocol_header = 0,
        connection_start_ok = @bitCast(Connection.StartOk.header),
        connection_secure_ok = @bitCast(Connection.SecureOk.header),
        connection_tune_ok = @bitCast(Connection.TuneOk.header),
        connection_open = @bitCast(Connection.Open.header),
        connection_close = @bitCast(Connection.Close.header),
        connection_close_ok = @bitCast(Connection.CloseOk.header),
        connection_blocked = @bitCast(Connection.Blocked.header),
        connection_unblocked = @bitCast(Connection.Unblocked.header),
        connection_update_secret_ok = @bitCast(Connection.UpdateSecretOk.header),
        channel_open = @bitCast(Channel.Open.header),
        channel_flow = @bitCast(Channel.Flow.header),
        channel_flow_ok = @bitCast(Channel.FlowOk.header),
        channel_close = @bitCast(Channel.Close.header),
        channel_close_ok = @bitCast(Channel.CloseOk.header),
        exchange_declare = @bitCast(Exchange.Declare.header),
        exchange_delete = @bitCast(Exchange.Delete.header),
        exchange_bind = @bitCast(Exchange.Bind.header),
        exchange_unbind = @bitCast(Exchange.Unbind.header),
        queue_declare = @bitCast(Queue.Declare.header),
        queue_bind = @bitCast(Queue.Bind.header),
        queue_unbind = @bitCast(Queue.Unbind.header),
        queue_purge = @bitCast(Queue.Purge.header),
        queue_delete = @bitCast(Queue.Delete.header),
        basic_qos = @bitCast(Basic.Qos.header),
        basic_consume = @bitCast(Basic.Consume.header),
        basic_cancel = @bitCast(Basic.Cancel.header),
        basic_cancel_ok = @bitCast(Basic.CancelOk.header),
        basic_publish = @bitCast(Basic.Publish.header),
        basic_get = @bitCast(Basic.Get.header),
        basic_ack = @bitCast(Basic.Ack.header),
        basic_reject = @bitCast(Basic.Reject.header),
        basic_recover_async = @bitCast(Basic.RecoverAsync.header),
        basic_recover = @bitCast(Basic.Recover.header),
        basic_nack = @bitCast(Basic.Nack.header),
        tx_select = @bitCast(Tx.Select.header),
        tx_commit = @bitCast(Tx.Commit.header),
        tx_rollback = @bitCast(Tx.Rollback.header),
        confirm_select = @bitCast(Confirm.Select.header),
    };

    protocol_header,
    connection_start_ok: Connection.StartOk,
    connection_secure_ok: Connection.SecureOk,
    connection_tune_ok: Connection.TuneOk,
    connection_open: Connection.Open,
    connection_close: Connection.Close,
    connection_close_ok: Connection.CloseOk,
    connection_blocked: Connection.Blocked,
    connection_unblocked: Connection.Unblocked,
    connection_update_secret_ok: Connection.UpdateSecretOk,
    channel_open: Channel.Open,
    channel_flow: Channel.Flow,
    channel_flow_ok: Channel.FlowOk,
    channel_close: Channel.Close,
    channel_close_ok: Channel.CloseOk,
    exchange_declare: Exchange.Declare,
    exchange_delete: Exchange.Delete,
    exchange_bind: Exchange.Bind,
    exchange_unbind: Exchange.Unbind,
    queue_declare: Queue.Declare,
    queue_bind: Queue.Bind,
    queue_unbind: Queue.Unbind,
    queue_purge: Queue.Purge,
    queue_delete: Queue.Delete,
    basic_qos: Basic.Qos,
    basic_consume: Basic.Consume,
    basic_cancel: Basic.Cancel,
    basic_cancel_ok: Basic.CancelOk,
    basic_publish: Basic.Publish,
    basic_get: Basic.Get,
    basic_ack: Basic.Ack,
    basic_reject: Basic.Reject,
    basic_recover_async: Basic.RecoverAsync,
    basic_recover: Basic.Recover,
    basic_nack: Basic.Nack,
    tx_select: Tx.Select,
    tx_commit: Tx.Commit,
    tx_rollback: Tx.Rollback,
    confirm_select: Confirm.Select,

    /// The expected response for synchronous methods,
    /// or `null` for asynchronous ones.
    pub fn response(self: SendMethod) ?ReceiveMethod.Tag {
        return switch (self) {
            .protocol_header => .connection_start,
            .connection_open => .connection_open_ok,
            .connection_close => .connection_close_ok,
            .channel_open => .channel_open_ok,
            .channel_flow => .channel_flow_ok,
            .channel_close => .channel_close_ok,
            .exchange_declare => .exchange_declare_ok,
            .exchange_delete => .exchange_delete_ok,
            .exchange_bind => .exchange_bind_ok,
            .exchange_unbind => .exchange_unbind_ok,
            .queue_declare => .queue_declare_ok,
            .queue_bind => .queue_bind_ok,
            .queue_unbind => .queue_unbind_ok,
            .queue_purge => .queue_purge_ok,
            .queue_delete => .queue_delete_ok,
            .basic_qos => .basic_qos_ok,
            .basic_consume => .basic_consume_ok,
            .basic_cancel => .basic_cancel_ok,
            .basic_get => .basic_get_ok,
            .tx_select => .tx_select_ok,
            .tx_commit => .tx_commit_ok,
            .tx_rollback => .tx_rollback_ok,
            .confirm_select => .confirm_select_ok,
            else => null,
        };
    }

    pub fn write(self: SendMethod, channel: u16, writer: *Writer) void {
        switch (self) {
            .protocol_header => {
                const header: []const u8 = "AMQP\x00\x00\x09\x01";
                writer.write_body(header);
            },
            inline else => |method| {
                const frame_reference = writer.begin_frame(.{
                    .type = .method,
                    .channel = channel,
                    .size = 0,
                });
                const Method = @TypeOf(method);
                writer.write_method_header(Method.header);
                method.write(writer);
                writer.finish_frame(frame_reference);
            },
        }
    }
};
